1	/**
2	 * 任务1-4: factor_baselines.json 初始化 + 阶段标签修正 + SOON层建卡 + 冷层/冷冻分层
3	 *
4	 * 输入: heat_classification.json (466人)
5	 * 输出: factor_baselines.json, SOON清单, 冷层/冷冻层清单
6	 */
7	
8	const fs = require('fs');
9	const path = require('path');
10	
11	const TODAY = '2026-05-17';
12	const TODAY_DATE = new Date(TODAY);
13	
14	// ============ 配置 ============
15	
16	/** 旧阶段 → 新9阶段映射 */
17	const STAGE_MAP = {
18	  '需求探索': '需求探索',
19	  '报价已发': '报价已发',
20	  '谈判中': '谈判中',
21	  '待付款': '待付款',
22	  '待发货': '待发货',
23	  '已发货/在途': '已发货/在途',
24	  '已签收': '已签收',
25	  '售后': '售后',
26	  '待返单': '待返单',
27	  // 旧标签映射
28	  '初询沟通': '需求探索',
29	  'PI已发': '报价已发',
30	  '谈判/样品': '谈判中',
31	  '样品阶段': '谈判中',  // 保守: 未付款→谈判中
32	  // 未知保持null→冷层
33	  '未知': null,
34	};
35	
36	/** SOON因子节奏表 (V5) */
37	const RHYTHM = {
38	  S1:  [1, 2, 3, 5, 7, 9, 15, 30],  // 需求探索 该深挖需求了
39	  S2:  [1, 3, 5, 15, 30],            // 报价已发 该追问了
40	  S3:  [1, 3, 5, 7, 15, 30],         // 谈判中 该推进了
41	  S4:  [1, 3, 5, 7],                  // 待付款 该催款了 (+每7天观察)
42	  S8:  [1, 2, 3, 5, 7, 15, 30],      // 售后 该收尾了
43	  S7a: [3, 15, 15, 30, 30, 60],       // 已签收 该回访了 (累计)
44	  S7b_sample: [7],                     // 样品单 该推返单
45	  S7b_bulk: [30],                      // 大货 该推返单
46	  S9_sample: [3, 7, 7, 15, 15, 30, 30],
47	  S9_bulk:   [7, 15, 15, 30, 30, 60, 60],
48	};
49	
50	/** S5a 双基线间隔计算 */
51	function s5aInterval(meta) {
52	  if (meta.customer_type === '样品单') return 3;
53	  if (!meta.transit_days) return 7; // 默认大货交期35天÷5≈7
54	  const interval = Math.round(meta.transit_days / 5);
55	  return Math.max(3, Math.min(10, interval));
56	}
57	
58	/** S6 间隔: 时效÷N */
59	function s6Interval(meta) {
60	  const transitDays = meta.transit_days || 25;
61	  const N = { S: 6, A: 6, B: 5, C: 5, D: 4 }[meta.customer_tier] || 5;
62	  const interval = Math.round(transitDays / N);
63	  return Math.max(2, Math.min(15, interval));
64	}
65	
66	// ============ 辅助函数 ============
67	
68	function parseDate(str) {
69	  if (!str) return null;
70	  const d = new Date(str);
71	  return isNaN(d.getTime()) ? null : d;
72	}
73	
74	function daysBetween(d1, d2) {
75	  return Math.floor((d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24));
76	}
77	
78	/** 判定节奏命中：返回命中的天数索引，未命中返回-1 */
79	function rhythmHit(days, rhythmArr) {
80	  // 找到 days 落在哪个间隔的 ±0 容差内 (当天命中)
81	  for (let i = 0; i < rhythmArr.length; i++) {
82	    const cumulative = rhythmArr.slice(0, i + 1).reduce((a, b) => a + b, 0);
83	    if (days === cumulative) return i;
84	  }
85	  return -1;
86	}
87	
88	/** 获取客户等级 (从 dashboard_snapshot 交叉匹配或默认) */
89	let tierMap = null;
90	function loadTierMap() {
91	  if (tierMap) return tierMap;
92	  tierMap = new Map();
93	  try {
94	    const snap = JSON.parse(fs.readFileSync(
95	      path.join(__dirname, '..', 'output', '.dashboard_snapshot.json'), 'utf-8'
96	    ));
97	    for (const c of snap.customers || []) {
98	      const key = (c.name || '').toLowerCase() + '|' + (c.country || '');
99	      tierMap.set(key, c.quality || 'C');
100	    }
101	  } catch (e) { /* ignore */ }
102	  return tierMap;
103	}
104	
105	function getTier(name, country) {
106	  const map = loadTierMap();
107	  return map.get((name || '').toLowerCase() + '|' + (country || '')) || 'C';
108	}
109	
110	/** 判定 target_market 是否非洲/中东 */
111	function isAfricaOrMiddleEast(country) {
112	  const africaME = ['SD','EG','CD','ZM','CI','SA','AE','IQ','GH','NG','KE','TZ','UG','ET','CM','SN','ML','BF','BJ','TG','LY','MA','DZ','TN','KW','QA','BH','OM','JO','LB','YE','SY','PS'];
113	  return africaME.includes((country || '').toUpperCase());
114	}
115	
116	// ============ 主流程 ============
117	
118	function main() {
119	  // 读取源数据
120	  const srcPath = path.join(__dirname, '..', 'data', 'heat_classification.json');
121	  const data = JSON.parse(fs.readFileSync(srcPath, 'utf-8'));
122	  const customers = data.results;
123	  console.log(`读取 ${customers.length} 条客户记录`);
124	
125	  const baselines = {};
126	  const stageStats = {};       // 新阶段统计
127	  const stageCorrections = []; // 阶段修正记录
128	  const soonCustomers = [];    // SOON层清单
129	  const coldCustomers = [];    // 冷层清单
130	  const frozenLayers = {       // 冷冻层分层
131	    highValue: [],   // 高价值沉睡
132	    normal: [],      // 普通沉睡
133	    neverDeal: [],   // 从未成交
134	  };
135	
136	  for (const c of customers) {
137	    const oldStage = c.stage;
138	    const newStage = STAGE_MAP[oldStage];
139	
140	    // 统计
141	    stageStats[oldStage] = (stageStats[oldStage] || 0) + 1;
142	    if (oldStage !== newStage && newStage !== null) {
143	      stageCorrections.push({ cid: c.cid, name: c.name, oldStage, newStage });
144	    }
145	
146	    const tier = getTier(c.name, c.country);
147	    const lastMsgDate = parseDate(c.lastMsgTime);
148	    const daysSinceMsg = lastMsgDate ? daysBetween(lastMsgDate, TODAY_DATE) : 999;
149	    const lastSenderIsMe = c.lastSender === '我';
150	
151	    // 初始化 meta
152	    const meta = {
153	      transit_days: null,
154	      customer_tier: tier,
155	      committed_ship_date: null,
156	      has_address: false,
157	      customer_type: (oldStage === '样品阶段') ? '样品单' : '大货',
158	      repurchase_cycle_days: null,
159	      target_market: isAfricaOrMiddleEast(c.country) ? 'africa_me' : 'other',
160	      s8_boundary_checked: false,
161	    };
162	
163	    // 初始化 baselines (全部 null)
164	    const bl = { S1: null, S2: null, S3: null, S4: null, S5a_A: null, S5a_B: null, S5b: null, S6: null, S7a: null, S7b: null, S8: null, S9: null };
165	
166	    const stageUpdated = c.lastMsgTime; // proxy
167	
168	    if (newStage) {
169	      // 根据阶段设置对应基线
170	      switch (newStage) {
171	        case '需求探索':
172	          if (lastSenderIsMe) bl.S1 = c.lastMsgTime;
173	          break;
174	        case '报价已发':
175	          bl.S2 = c.lastMsgTime;
176	          break;
177	        case '谈判中':
178	          bl.S3 = c.lastMsgTime;
179	          break;
180	        case '待付款':
181	          bl.S4 = c.lastMsgTime;
182	          break;
183	        case '待发货':
184	          if (lastSenderIsMe) bl.S5a_A = c.lastMsgTime;
185	          bl.S5b = c.lastMsgTime; // proxy for 付款到账日
186	          break;
187	        case '已发货/在途':
188	          bl.S6 = c.lastMsgTime;
189	          meta.transit_days = isAfricaOrMiddleEast(c.country) ? 30 : 25;
190	          break;
191	        case '已签收':
192	          bl.S7a = c.lastMsgTime;
193	          bl.S7b = c.lastMsgTime;
194	          break;
195	        case '售后':
196	          if (lastSenderIsMe) bl.S8 = c.lastMsgTime;
197	          break;
198	        case '待返单':
199	          bl.S9 = c.lastMsgTime;
200	          break;
201	      }
202	
203	      // 计算 SOON 因子命中
204	      const factors = computeFactors(newStage, bl, meta, daysSinceMsg, lastSenderIsMe);
205	
206	      baselines[c.cid] = {
207	        name: c.name,
208	        country: c.country,
209	        stage: newStage,
210	        stage_updated: stageUpdated,
211	        baselines: bl,
212	        meta,
213	        _heat: c.heat,
214	        _daysSinceLastContact: c.daysSinceLastContact,
215	      };
216	
217	      if (factors.length > 0) {
218	        soonCustomers.push({
219	          cid: c.cid,
220	          name: c.name,
221	          country: c.country,
222	          stage: newStage,
223	          heat: c.heat,
224	          tier,
225	          daysSinceLastContact: c.daysSinceLastContact,
226	          factors,
227	        });
228	      }
229	    } else {
230	      // 未知阶段 → 冷层
231	      baselines[c.cid] = {
232	        name: c.name,
233	        country: c.country,
234	        stage: null,
235	        stage_updated: null,
236	        baselines: bl,
237	        meta,
238	        _heat: c.heat,
239	        _daysSinceLastContact: c.daysSinceLastContact,
240	      };
241	      coldCustomers.push({
242	        cid: c.cid,
243	        name: c.name,
244	        country: c.country,
245	        daysSinceLastContact: c.daysSinceLastContact,
246	        tier,
247	        lastMsgTime: c.lastMsgTime,
248	        lastSender: c.lastSender,
249	      });
250	    }
251	  }
252	
253	  // 冷冻层分层
254	  for (const cc of coldCustomers) {
255	    if (cc.daysSinceLastContact > 180) {
256	      frozenLayers.highValue.push(cc); // 超180天归档
257	    } else if (cc.tier === 'A' || cc.tier === 'B') {
258	      frozenLayers.highValue.push(cc); // 高价值沉睡
259	    } else if (cc.tier === 'D') {
260	      frozenLayers.neverDeal.push(cc); // D级=从未成交/个人买家
261	    } else {
262	      frozenLayers.normal.push(cc);
263	    }
264	  }
265	
266	  // ==== 输出统计 ====
267	  console.log('\n===== 阶段映射统计 =====');
268	  for (const [k, v] of Object.entries(stageStats).sort((a, b) => b[1] - a[1])) {
269	    const mapped = STAGE_MAP[k];
270	    const arrow = mapped === k ? '→ 不变' : mapped === null ? '→ 冷层' : `→ ${mapped}`;
271	    console.log(`  ${k}: ${v} ${arrow}`);
272	  }
273	
274	  const newStageCounts = {};
275	  for (const v of Object.values(baselines)) {
276	    const s = v.stage || '未知(冷层)';
277	    newStageCounts[s] = (newStageCounts[s] || 0) + 1;
278	  }
279	  console.log('\n===== 新9阶段分布 =====');
280	  for (const [k, v] of Object.entries(newStageCounts).sort((a, b) => b[1] - a[1])) {
281	    console.log(`  ${k}: ${v}`);
282	  }
283	
284	  console.log(`\n===== SOON层: ${soonCustomers.length}人 =====`);
285	  console.log(`===== 冷层: ${coldCustomers.length}人 =====`);
286	  console.log(`  高价值沉睡: ${frozenLayers.highValue.length}`);
287	  console.log(`  普通沉睡: ${frozenLayers.normal.length}`);
288	  console.log(`  从未成交: ${frozenLayers.neverDeal.length}`);
289	
290	  // ==== 写入文件 ====
291	
292	  // 1. factor_baselines.json
293	  const outDir = path.join(__dirname, '..', 'output');
294	  const baselinesOut = {};
295	  for (const [cid, val] of Object.entries(baselines)) {
296	    const { _heat, _daysSinceLastContact, ...rest } = val;
297	    baselinesOut[cid] = rest;
298	  }
299	  fs.writeFileSync(
300	    path.join(outDir, 'factor_baselines.json'),
301	    JSON.stringify(baselinesOut, null, 2),
302	    'utf-8'
303	  );
304	  console.log('\n✅ factor_baselines.json 已写入');
305	
306	  // 2. 阶段修正记录
307	  fs.writeFileSync(
308	    path.join(outDir, 'stage_corrections.json'),
309	    JSON.stringify({ date: TODAY, corrections: stageCorrections, total: stageCorrections.length }, null, 2),
310	    'utf-8'
311	  );
312	  console.log(`✅ stage_corrections.json 已写入 (${stageCorrections.length}条修正)`);
313	
314	  // 3. SOON层清单
315	  const soonOutput = {
316	    date: TODAY,
317	    total: soonCustomers.length,
318	    summary: summarizeFactors(soonCustomers),
319	    customers: soonCustomers.sort((a, b) => {
320	      // NOW优先，然后按因子数降序
321	      if (a.heat === 'NOW' && b.heat !== 'NOW') return -1;
322	      if (b.heat === 'NOW' && a.heat !== 'NOW') return 1;
323	      return b.factors.length - a.factors.length;
324	    }),
325	  };
326	  fs.writeFileSync(
327	    path.join(outDir, 'soon_layer_cards.json'),
328	    JSON.stringify(soonOutput, null, 2),
329	    'utf-8'
330	  );
331	  console.log(`✅ soon_layer_cards.json 已写入`);
332	
333	  // 4. 冷层+冷冻分层
334	  const coldOutput = {
335	    date: TODAY,
336	    total: coldCustomers.length,
337	    frozen: {
338	      highValueDormant: frozenLayers.highValue,
339	      normalDormant: frozenLayers.normal,
340	      neverDeal: frozenLayers.neverDeal,
341	    },
342	  };
343	  fs.writeFileSync(
344	    path.join(outDir, 'cold_layer_stratification.json'),
345	    JSON.stringify(coldOutput, null, 2),
346	    'utf-8'
347	  );
348	  console.log(`✅ cold_layer_stratification.json 已写入`);
349	
350	  // 5. 汇总报告 (markdown)
351	  const report = generateReport(newStageCounts, soonOutput, coldOutput, stageCorrections);
352	  fs.writeFileSync(path.join(outDir, 'init_report_2026-05-17.md'), report, 'utf-8');
353	  console.log(`✅ init_report_2026-05-17.md 已写入`);
354	}
355	
356	/** 计算SOON因子命中 */
357	function computeFactors(stage, bl, meta, daysSinceMsg, lastSenderIsMe) {
358	  const factors = [];
359	  const t = TODAY_DATE;
360	
361	  function check(baselineKey, rhythmArr, factorName, opts = {}) {
362	    const bDate = parseDate(bl[baselineKey]);
363	    if (!bDate) return;
364	    const days = daysBetween(bDate, t);
365	    if (days < 1) return; // 今天刚设基线，不触发
366	
367	    const hitIdx = rhythmHit(days, rhythmArr);
368	    if (hitIdx >= 0) {
369	      const cumulative = rhythmArr.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
370	      factors.push({
371	        factor: factorName,
372	        days,
373	        rhythmDay: cumulative,
374	        intervalIndex: hitIdx,
375	        baseline: bl[baselineKey],
376	        ...opts,
377	      });
378	    }
379	  }
380	
381	  switch (stage) {
382	    case '需求探索':
383	      check('S1', RHYTHM.S1, 'S1 该深挖需求了');
384	      break;
385	    case '报价已发':
386	      check('S2', RHYTHM.S2, 'S2 该追问了');
387	      break;
388	    case '谈判中':
389	      check('S3', RHYTHM.S3, 'S3 该推进了');
390	      break;
391	    case '待付款':
392	      check('S4', RHYTHM.S4, 'S4 该催款了');
393	      // 超过Day7后每7天观察
394	      if (bl.S4) {
395	        const days = daysBetween(parseDate(bl.S4), t);
396	        if (days > 7 && days % 7 === 0) {
397	          factors.push({ factor: 'S4 该催款了(观察)', days, baseline: bl.S4, observeMode: true });
398	        }
399	      }
400	      break;
401	    case '待发货':
402	      // S5a: 双基线
403	      if (bl.S5a_A) {
404	        const daysA = daysBetween(parseDate(bl.S5a_A), t);
405	        const interval = s5aInterval(meta);
406	        if (daysA >= interval && daysA % interval === 0) {
407	          factors.push({ factor: 'S5a 该更新进度了', days: daysA, interval, baseline: bl.S5a_A, priority: 'normal' });
408	        }
409	      }
410	      if (meta.committed_ship_date) {
411	        const shipDate = parseDate(meta.committed_ship_date);
412	        if (shipDate && t > shipDate) {
413	          const overdue = daysBetween(shipDate, t);
414	          factors.push({ factor: 'S5a 该更新进度了(超期)', days: overdue, priority: 'high', reason: '超承诺发货日' });
415	        }
416	      }
417	      // S5b: 该要地址了
418	      if (!meta.has_address && bl.S5b) {
419	        const days = daysBetween(parseDate(bl.S5b), t);
420	        if (days >= 1) {
421	          factors.push({ factor: 'S5b 该要地址了', days, baseline: bl.S5b });
422	        }
423	      }
424	      break;
425	    case '已发货/在途':
426	      check('S6', [s6Interval(meta)], 'S6 该更新物流了', { interval: s6Interval(meta) });
427	      break;
428	    case '已签收':
429	      check('S7a', RHYTHM.S7a, 'S7a 该回访了');
430	      if (bl.S7b) {
431	        const rhythm = meta.customer_type === '样品单' ? RHYTHM.S7b_sample : RHYTHM.S7b_bulk;
432	        check('S7b', rhythm, 'S7b 该推返单了');
433	      }
434	      break;
435	    case '售后':
436	      check('S8', RHYTHM.S8, 'S8 该收尾了');
437	      break;
438	    case '待返单':
439	      if (bl.S9) {
440	        const rhythm = meta.customer_type === '样品单' ? RHYTHM.S9_sample : RHYTHM.S9_bulk;
441	        check('S9', rhythm, 'S9 该接触了');
442	      }
443	      break;
444	  }
445	
446	  return factors;
447	}
448	
449	/** 因子命中统计 */
450	function summarizeFactors(soonCustomers) {
451	  const factorCounts = {};
452	  for (const c of soonCustomers) {
453	    for (const f of c.factors) {
454	      const key = f.factor.split('(')[0].trim();
455	      factorCounts[key] = (factorCounts[key] || 0) + 1;
456	    }
457	  }
458	  return factorCounts;
459	}
460	
461	/** 生成 markdown 报告 */
462	function generateReport(newStageCounts, soonOutput, coldOutput, corrections) {
463	  const lines = [
464	    `# OKKI SOON 层初始化报告`,
465	    `> 日期: ${TODAY}`,
466	    `> 数据源: heat_classification.json (466人)`,
467	    ``,
468	    `## 一、阶段标签修正`,
469	    ``,
470	    `| 旧标签 | 新标签 | 人数 |`,
471	    `|--------|--------|------|`,
472	  ];
473	  const oldCounts = {};
474	  for (const corr of corrections) {
475	    oldCounts[corr.oldStage] = (oldCounts[corr.oldStage] || 0) + 1;
476	  }
477	  for (const [old, count] of Object.entries(oldCounts)) {
478	    lines.push(`| ${old} | ${STAGE_MAP[old]} | ${count} |`);
479	  }
480	  lines.push(`| (其他) | 不变 | ${466 - corrections.length - coldOutput.total} |`);
481	  lines.push('');
482	
483	  lines.push(`## 二、新9阶段分布`);
484	  lines.push('');
485	  lines.push(`| 阶段 | 人数 |`);
486	  lines.push(`|------|------|`);
487	  for (const [k, v] of Object.entries(newStageCounts).sort((a, b) => b[1] - a[1])) {
488	    lines.push(`| ${k} | ${v} |`);
489	  }
490	  lines.push('');
491	
492	  lines.push(`## 三、SOON 层`);
493	  lines.push('');
494	  lines.push(`- **总计**: ${soonOutput.total} 人命中 SOON 因子`);
495	  lines.push(`- **因子分布**:`);
496	  for (const [factor, count] of Object.entries(soonOutput.summary)) {
497	    lines.push(`  - ${factor}: ${count}人`);
498	  }
499	  lines.push('');
500	
501	  lines.push(`## 四、冷层 & 冷冻分层`);
502	  lines.push('');
503	  lines.push(`- **冷层总计**: ${coldOutput.total} 人`);
504	  lines.push(`  - 高价值沉睡 (A/B级或>180天): ${coldOutput.frozen.highValueDormant.length} 人`);
505	  lines.push(`  - 普通沉睡: ${coldOutput.frozen.normalDormant.length} 人`);
506	  lines.push(`  - 从未成交 (D级): ${coldOutput.frozen.neverDeal.length} 人`);
507	  lines.push('');
508	
509	  lines.push(`## 五、产出文件`);
510	  lines.push('');
